/**
 * Get the ns uri of the specified node.
 * @param node Node to check
 * @return String ns uri
 */
public static String getNamespaceURI(Node node) {
    if (node instanceof Document) {
        node = ((Document) node).getDocumentElement();
    }

    // Only Element nodes have direct namespace URIs
    if (node instanceof Element) {
        Element element = (Element) node;

        String uri = element.getNamespaceURI();
        if (uri != null) {
            return uri;
        }

        String prefix = getPrefix(node);
        String qname = prefix == null ? "xmlns" : "xmlns:" + prefix;

        Node aNode = node;
        while (aNode != null) {
            if (aNode.getNodeType() == Node.ELEMENT_NODE) {
                Attr attr = ((Element) aNode).getAttributeNode(qname);
                if (attr != null) {
                    return attr.getValue();
                }
            }
            aNode = aNode.getParentNode();
        }
    }
    else {
        // For non-element nodes, we need to look for namespace declarations
        // in parent elements only, since the node itself doesn't have namespace attributes
        Node aNode = node.getParentNode();
        while (aNode != null) {
            if (aNode.getNodeType() == Node.ELEMENT_NODE) {
                // For namespace lookup on non-element nodes, 
                // we check for default namespace xmlns
                Attr attr = ((Element) aNode).getAttributeNode("xmlns");
                if (attr != null) {
                    return attr.getValue();
                }
            }
            aNode = aNode.getParentNode();
        }
    }

    return null;
}

